import { useEffect, useState, useCallback } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from "@/components/ui/dialog";
import { apiClient, authService } from "@/App";
import { toast } from "sonner";
import { Plus, FileText } from "lucide-react";
import jsPDF from "jspdf";

const ExamsPage = () => {
  const [exams, setExams] = useState([]);
  const [loading, setLoading] = useState(true);
  const [dialogOpen, setDialogOpen] = useState(false);

  const [formData, setFormData] = useState({
    name: "",
    class_name: "",
    year_of_study: "",
    term: "Term 1",
    exam_number: "Exam 1",
    academic_year: new Date().getFullYear().toString(),
    exam_date: ""
  });

  const kenyaClasses = [
    "PP1","PP2","Grade 1","Grade 2","Grade 3","Grade 4","Grade 5","Grade 6",
    "Grade 7","Grade 8","Grade 9","Grade 10","Grade 11","Grade 12"
  ];

  const collegeYears = ["Year 1","Year 2","Year 3","Year 4","Year 5","Year 6"];

  // =========================
  // SAFE FETCH (FIXED)
  // =========================
  const fetchExams = useCallback(async () => {
    const token = authService.getToken();

    if (!token) {
      setLoading(false);
      setExams([]);
      return;
    }

    try {
      setLoading(true);

      const response = await apiClient.get("/exams");

      setExams(Array.isArray(response?.data) ? response.data : []);

    } catch (error) {
      const status = error?.response?.status;

      if (status === 401) {
        toast.error("Session expired. Please login again.");
        authService.clearAuth();
        window.location.href = "/login";
      } else {
        toast.error("Failed to fetch exams");
      }

      setExams([]);

    } finally {
      setLoading(false);
    }
  }, []);

  // =========================
  // INIT LOAD (FIXED)
  // =========================
  useEffect(() => {
    const token = authService.getToken();
    if (!token) {
      setLoading(false);
      return;
    }

    fetchExams();
  }, [fetchExams]);

  // =========================
  // CREATE EXAM
  // =========================
  const handleSubmit = async (e) => {
    e.preventDefault();

    try {
      await apiClient.post("/exams", formData);

      toast.success("Exam created successfully");
      setDialogOpen(false);

      fetchExams();

    } catch (error) {
      toast.error(
        error?.response?.data?.detail ||
        error?.message ||
        "Failed to create exam"
      );
    }
  };

  // =========================
  // REPORT
  // =========================
  const generateReport = () => {
    const doc = new jsPDF();

    doc.setFontSize(20);
    doc.text("Smart Hub - Exam Report", 20, 20);

    doc.setFontSize(12);
    doc.text(`Generated: ${new Date().toLocaleDateString()}`, 20, 30);

    let y = 50;

    exams.forEach((exam, index) => {
      if (y > 270) {
        doc.addPage();
        y = 20;
      }

      doc.text(`${index + 1}. ${exam.name || "Unnamed Exam"}`, 20, y);
      y += 7;

      doc.text(
        `Class: ${exam.class_name || exam.year_of_study || "N/A"} | ${exam.term || "N/A"} | ${exam.exam_number || "N/A"}`,
        20,
        y
      );

      y += 7;

      doc.text(
        `Date: ${exam.exam_date ? new Date(exam.exam_date).toLocaleDateString() : "N/A"}`,
        20,
        y
      );

      y += 10;
    });

    doc.save(`exam-report-${Date.now()}.pdf`);
    toast.success("Report downloaded");
  };

  // =========================
  // UI
  // =========================
  return (
    <div className="space-y-6">

      {/* HEADER */}
      <div className="flex items-center justify-between">
        <div>
          <h2 className="text-3xl font-bold text-white">
            Performance & Assessments
          </h2>
          <p className="text-slate-400 mt-1">
            Manage examinations using CBE grading
          </p>
        </div>

        <div className="flex gap-2">
          <Button variant="outline" onClick={generateReport}>
            <FileText className="w-4 h-4 mr-2" />
            Download Report
          </Button>

          <Dialog open={dialogOpen} onOpenChange={setDialogOpen}>
            <DialogTrigger asChild>
              <Button>
                <Plus className="w-4 h-4 mr-2" />
                Create Exam
              </Button>
            </DialogTrigger>

            <DialogContent className="max-w-2xl">
              <DialogHeader>
                <DialogTitle>Create New Exam</DialogTitle>
              </DialogHeader>

              <form onSubmit={handleSubmit} className="space-y-4">

                <div className="space-y-2">
                  <Label>Exam Name</Label>
                  <Input
                    value={formData.name}
                    onChange={(e) =>
                      setFormData({ ...formData, name: e.target.value })
                    }
                    required
                  />
                </div>

                <div className="space-y-2">
                  <Label>Exam Date</Label>
                  <Input
                    type="date"
                    value={formData.exam_date}
                    onChange={(e) =>
                      setFormData({ ...formData, exam_date: e.target.value })
                    }
                    required
                  />
                </div>

                <Button type="submit" className="w-full">
                  Create Exam
                </Button>

              </form>
            </DialogContent>
          </Dialog>
        </div>
      </div>

      {/* LOADING */}
      {loading && (
        <Card>
          <CardContent className="py-10 text-center">
            Loading exams...
          </CardContent>
        </Card>
      )}

      {/* EMPTY STATE */}
      {!loading && exams.length === 0 && (
        <Card>
          <CardContent className="py-10 text-center text-slate-500">
            No exams found. Create your first exam.
          </CardContent>
        </Card>
      )}

    </div>
  );
};

export default ExamsPage;
